mapper.select:
SELECT et.id AS evalTypeId, etm.evaluator_no AS evaluatorNo, eval_emp.name AS evaluatorName, etm.evaluatee_no AS evaluateeNo, e.name AS evaluateeName, et.name AS evalName, etm.step, e.dept_id AS deptId, d.name AS deptName, e.position AS position, e.emp_no AS empNo, et.start_date AS startDate, et.end_date AS endDate, cc.name AS statusName FROM eval_target_mapping_52 etm JOIN eval_type_52 et ON et.id = etm.eval_type_id JOIN employee_52 e ON e.emp_no = etm.evaluatee_no LEFT JOIN department_52 d ON d.id = e.dept_id LEFT JOIN employee_52 eval_emp ON eval_emp.emp_no = etm.evaluator_no LEFT JOIN code_common_52 cc ON cc.code = CAST(etm.status AS VARCHAR) LEFT JOIN code_group_52 cg ON cg.id = cc.group_id AND cg.group_code = 'EVAL_STATUS'
et.name LIKE '%다면평가%'
AND etm.evaluator_no = #{userNo}
AND etm.evaluatee_no = #{userNo}

SELECT q.id AS questionId, q.category AS categoryName, q.explanation AS explanation, q.question AS question, q.question_type AS questionType, q.weight AS weight, ea.score AS selfScore, ea.content AS selfFeedback, etm.id AS mappingId FROM eval_question_52 q
-- 1. 평가자 + 피평가자 기준 매핑 LEFT JOIN eval_target_mapping_52 etm ON etm.eval_type_id = q.type_id AND etm.evaluator_no = #{loginEmpNo} AND etm.evaluatee_no = #{empNo}
-- 2. 매핑에 해당하는 답변 LEFT JOIN eval_answer_52 ea ON ea.question_id = q.id AND ea.mapping_id = etm.id
WHERE q.type_id = #{evalTypeId}
